import React, { useCallback, useEffect, useMemo, useState } from 'react';
import {
  Select,
  Pagination,
  StatusBadge,
  detectDateRangePreset,
  SearchTextInput,
  dispatchAppToast,
  LIN_ERP_LIST_FILTER_LAYOUT,
  LinErpListFilterBar,
  LinPageLayout,
  LinListTableConfigModal,
  loadErpListTableConfig,
  saveErpListTableConfig,
  useCatalogTableBusy,
  type ErpListTableConfig,
} from '@linm-soft-org/linm-web-common-components';
import { useAppDispatch } from '../../../store/hooks';
import { useThanhPhamLoiListFilterState } from '../../../hooks/useThanhPhamLoiListFilterState';
import { useFgIssuePermissions } from '../../../hooks/useFgIssuePermissions';
import { wmsService } from '../../../services/kho/wmsService';
import type { FgIssueDto } from '../../../services/kho/models';
import { VOUCHER_STATUS_OPTIONS, PAGE_SIZE } from '../../../utils/constants';
import { LIST_FILTER_SCOPE } from '../../../constants/listFilterScopes';
import { thanhPhamLoiPageLabels } from '../../../constants/thanhPhamLoiPageLabels';
import { formatDate, formatMoneyVnd } from '../../../utils/formatters';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import { ContractSearchField } from '../../../components/search';
import erp from '../../../styles/erpPage.module.css';

const TEST_ID = 'erp-kho-thanh-pham-loi';
const PAGE_ID = 'kho-thanh-pham-loi';

const ThanhPhamLoiPage: React.FC = () => {
  const dispatch = useAppDispatch();
  useFgIssuePermissions();
  const {
    initialized,
    fromDate,
    toDate,
    datePreset,
    applyDateRange,
    searchDraft,
    setSearchDraft,
    search,
    setSearch,
    status,
    setStatus,
    page,
    setPage,
    resetPage,
  } = useThanhPhamLoiListFilterState(LIST_FILTER_SCOPE.thanhPhamLoi);

  const [contractCode, setContractCode] = useState('');
  const [contractCustomerName, setContractCustomerName] = useState('');
  const [items, setItems] = useState<FgIssueDto[]>([]);
  const [totalCount, setTotalCount] = useState(0);
  const [loading, setLoading] = useState(false);
  const [reloadKey, setReloadKey] = useState(0);
  const [activeId, setActiveId] = useState<string | null>(null);
  const [configOpen, setConfigOpen] = useState(false);
  const [tableConfig, setTableConfig] = useState<ErpListTableConfig>(() =>
    loadErpListTableConfig(`${TEST_ID}-list-table-config`),
  );

  const refresh = useCallback(() => setReloadKey(k => k + 1), []);
  const handleSaveTableConfig = useCallback((next: ErpListTableConfig) => {
    setTableConfig(next);
    saveErpListTableConfig(`${TEST_ID}-list-table-config`, next);
  }, []);
  const handleSearch = useCallback(() => {
    setSearch(searchDraft.trim());
    resetPage();
  }, [searchDraft, setSearch, resetPage]);
  const { showTableLoading } = useCatalogTableBusy(loading);

  useEffect(() => {
    if (!initialized) return;
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      wmsService.getFgIssues({
        status: status || undefined,
        fromDate: fromDate ? `${fromDate}T00:00:00.000Z` : undefined,
        toDate: toDate ? `${toDate}T23:59:59.999Z` : undefined,
        contractCode: contractCode || undefined,
        search: search || undefined,
        page,
        pageSize: PAGE_SIZE,
      })
        .then(res => {
          if (cancelled) return;
          setItems(res.items);
          setTotalCount(res.totalCount);
        })
        .catch(err => {
          if (!cancelled) {
            dispatchAppToast(dispatch, {
              message: getApiErrorMessage(err, thanhPhamLoiPageLabels.loadError),
              type: 'error',
            });
          }
        })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [initialized, status, fromDate, toDate, contractCode, page, search, dispatch, reloadKey]);

  const voucherToolbar = useMemo(
    () => ({
      testIdPrefix: TEST_ID,
      onRefresh: refresh,
      onEditConfig: () => setConfigOpen(true),
    }),
    [refresh],
  );

  const listFilters = useMemo(
    () => (
      <LinErpListFilterBar
        testIdPrefix={TEST_ID}
        fromDate={fromDate}
        toDate={toDate}
        onDateChange={(from, to) => {
          applyDateRange(from, to, detectDateRangePreset(from, to) || 'custom');
          resetPage();
        }}
        onSearch={handleSearch}
        loading={showTableLoading}
        leading={(
          <>
            <div data-testid={`${TEST_ID}-field-search`}>
              <SearchTextInput
                label="Tìm kiếm"
                value={searchDraft}
                onChange={setSearchDraft}
                onSearch={handleSearch}
                placeholder={thanhPhamLoiPageLabels.searchPlaceholder}
                testId={`${TEST_ID}-search-text`}
              />
            </div>
            <div data-testid={`${TEST_ID}-field-contract`}>
              <ContractSearchField
                contractCode={contractCode}
                customerName={contractCustomerName}
                onSelect={(code, name) => {
                  setContractCode(code);
                  setContractCustomerName(name);
                  resetPage();
                }}
                onClear={() => {
                  setContractCode('');
                  setContractCustomerName('');
                  resetPage();
                }}
                placeholder={thanhPhamLoiPageLabels.contractPlaceholder}
              />
            </div>
            <div data-testid={`${TEST_ID}-field-status`}>
              <Select
                label="Trạng thái"
                value={status}
                onChange={e => { setStatus(e.target.value); resetPage(); }}
                options={VOUCHER_STATUS_OPTIONS}
                data-testid={`${TEST_ID}-filter-status`}
              />
            </div>
          </>
        )}
      />
    ),
    [
      fromDate,
      toDate,
      searchDraft,
      contractCode,
      contractCustomerName,
      status,
      applyDateRange,
      resetPage,
      setSearchDraft,
      handleSearch,
      setStatus,
      showTableLoading,
    ],
  );

  const listBody = !showTableLoading && items.length === 0 ? (
    <div className={erp.empty} data-testid={`${TEST_ID}-empty`}>
      <i className="fas fa-inbox" />
      <p>{thanhPhamLoiPageLabels.empty}</p>
    </div>
  ) : !showTableLoading ? (
    <div className={erp.tableWrapper} data-testid={`${TEST_ID}-grid`} data-sticky-header={tableConfig.stickyHeader || undefined}>
      <table className={erp.table}>
        <thead>
          <tr>
            <th>Số phiếu</th>
            <th>Ngày</th>
            <th>Kho</th>
            <th>HĐ</th>
            <th className={erp.colRight}>Tổng tiền</th>
            <th>Trạng thái</th>
          </tr>
        </thead>
        <tbody>
          {items.map(r => (
            <tr
              key={r.id}
              className={r.id === activeId ? erp.rowSelected : undefined}
              onClick={() => setActiveId(r.id)}
              data-testid={`${TEST_ID}-row-${r.id}`}
            >
              <td><code>{r.code}</code></td>
              <td>{formatDate(r.voucherDate)}</td>
              <td>{r.warehouseName}</td>
              <td>{r.contractCode ?? '—'}</td>
              <td className={erp.colRight}>{formatMoneyVnd(r.totalAmount)}</td>
              <td><StatusBadge status={r.status} /></td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  ) : null;

  return (
    <div className={erp.voucherListRoot} data-voucher-list-page data-testid={`${TEST_ID}-list`}>
      <LinPageLayout
        kind="voucher"
        testIdPrefix={TEST_ID}
        pageId={PAGE_ID}
        pageClassName={`${erp.catalogListPage} ${erp.voucherListPage}`}
        header={{
          title: thanhPhamLoiPageLabels.listTitle,
          titleIconClass: 'fas fa-exclamation-triangle',
          pageId: PAGE_ID,
        }}
        voucherToolbar={voucherToolbar}
        listTitle={thanhPhamLoiPageLabels.listSubtitle}
        listRowMenuHelp
        filters={listFilters}
        listLayoutVariant="erp-filter-bar"
        listHeaderClassName={LIN_ERP_LIST_FILTER_LAYOUT.header}
        listFiltersClassName={LIN_ERP_LIST_FILTER_LAYOUT.filtersHost}
        showTableLoading={showTableLoading}
        skeletonRows={6}
        modals={(
          <LinListTableConfigModal
            isOpen={configOpen}
            onClose={() => setConfigOpen(false)}
            testIdPrefix={TEST_ID}
            config={tableConfig}
            onSave={handleSaveTableConfig}
          />
        )}
        footer={(
          <div className={erp.paginationRow} data-testid={`${TEST_ID}-pagination`}>
            <span className={erp.totalCount}>Tổng: {totalCount} phiếu</span>
            <Pagination
              currentPage={page}
              totalPages={Math.max(1, Math.ceil(totalCount / PAGE_SIZE))}
              totalCount={totalCount}
              pageSize={PAGE_SIZE}
              onPageChange={p => { setPage(p); setActiveId(null); }}
            />
          </div>
        )}
      >
        {listBody}
      </LinPageLayout>
    </div>
  );
};

export default ThanhPhamLoiPage;
